import "../styles/about.css";

function About() {

  return (

    <section className="about">

      <div className="about-container">

        <h1>About Me</h1>

        <p>
          I'm a passionate frontend developer interested in
          building responsive and user-friendly web applications.
          I enjoy learning modern web technologies and creating
          clean UI designs.
        </p>

      </div>

    </section>

  );
}

export default About;
